+            continue;
+        }
+
+        let src_path = entry.path();
+        let dst_path = dst.join(file_name);
+        if file_type.is_dir() {
+            copy_fixture_workspace_recursive(&src_path, &dst_path)?;
+        } else if file_type.is_file() {
+            fs::copy(&src_path, &dst_path)?;
+        }
+    }
+
